along with GCC; see the file COPYING3.  If not see
<http://www.gnu.org/licenses/>.  */

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "cfganal.h"
#include "gimple-iterator.h"
#include "dumpfile.h"

namespace {

const pass_data pass_data_bb_count =
{
  GIMPLE_PASS, /* type */
  "bb_count", /* name */
  OPTGROUP_NONE, /* optinfo_flags */
  TV_NONE, /* tv_id */
  ( PROP_cfg ), /* properties_required */
  0, /* properties_provided */
  0, /* properties_destroyed */
  0, /* todo_flags_start */
  0, /* todo_flags_finish */
};

class pass_bb_count : public gimple_opt_pass
{
public:
  pass_bb_count (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_bb_count, ctxt)
  {}

  /* opt_pass methods: */
  opt_pass * clone () final override { return new pass_bb_count (m_ctxt); }
  bool gate (function *) final override { return true; }
  unsigned int execute (function *func) final override
    {
      basic_block bb;
      int bb_count = 0;

      /* Count the basic blocks in this function. */
      FOR_EACH_BB_FN (bb, func)
        {
          bb_count++;
        }

      /* Dump the result for debugging. */
      if (dump_file && (dump_flags & TDF_DETAILS))
        {
          fprintf (dump_file, "Basic block count for function %s: %d\n",
                   function_name (func), bb_count);
        }

      return 0;
    }

}; // class pass_bb_count

} // anon namespace

gimple_opt_pass *
make_pass_bb_count (gcc::context *ctxt)
{
  return new pass_bb_count (ctxt);
}

